script:
frappe.ui.form.on('Issue', {
    refresh: function (frm) {
        if (!frm.doc.__islocal) { // Fetch only for saved documents
            frappe.call({
                method: 'sys_api_whatsapp_chat', // Replace with the actual server script name
                args: {
                    issue_name: frm.doc.name // Ensure this matches the server script's parameter
                },
                callback: function (r) {
                    if (r.message) {
                        // Inject the response HTML into the custom field
                        frm.fields_dict.custom_whatsapp_chat.html(r.message);
                    } else {
                        frm.fields_dict.custom_whatsapp_chat.html('<div>No activity found.</div>');
                    }
                }
            });
        }
    }
});

frappe.ui.form.on('Issue', {
    refresh: function(frm) {
        // Apply dynamic filter when form is loaded
        frm.fields_dict['custom_contact_chat'].get_query = function(doc, cdt, cdn) {
            return {
                filters: {
                    'link_doctype': 'Customer',
                    'link_name': doc.customer
                }
            };
        };
    }
});

frappe.ui.form.on('Issue', {
    refresh: function (frm) {
        console.log('Refreshing form...'); // For debugging

        frm.add_custom_button(__("Send WhatsApp"), function () {
            console.log('Send WhatsApp button clicked');

            if (!frm.doc.custom_contact_chat) {
                frappe.msgprint({
                    title: __('Error'),
                    indicator: 'red',
                    message: __('No contact selected in the "custom_contact_chat" field.')
                });
                return;
            }

            // Fetch the contact details using frappe.call
            frappe.call({
                method: "frappe.client.get",
                args: {
                    doctype: "Contact",
                    name: frm.doc.custom_contact_chat
                },
                callback: function (response) {
                    console.log('API Response:', response);

                    if (response.message) {
                        let contact = response.message;

                        // Ensure contact has valid phone number
                        let contact_number = contact.mobile_no || contact.phone || null;
                        if (!contact_number) {
                            frappe.msgprint({
                                title: __('Error'),
                                indicator: 'red',
                                message: __('The selected contact has no phone or mobile number.')
                            });
                            return;
                        }

                        // Create a modal dialog for entering the WhatsApp message
                        let d = new frappe.ui.Dialog({
                            title: __('Send WhatsApp Message'),
                            fields: [
                                {
                                    label: 'To',
                                    fieldname: 'to',
                                    fieldtype: 'Data',
                                    default: contact_number,
                                    read_only: 1
                                },
                                {
                                    label: 'Content Type',
                                    fieldname: 'content_type',
                                    fieldtype: 'Select',
                                    options: ['text', 'image', 'document', 'audio', 'video'],
                                    default: 'text'
                                },
                                {
                                    label: 'Message',
                                    fieldname: 'message',
                                    fieldtype: 'Text'
                                },
                                {
                                    label: 'Attach File',
                                    fieldname: 'attach',
                                    fieldtype: 'Attach',
                                    depends_on: 'eval:doc.content_type != "text"'
                                }
                            ],
                            primary_action_label: __('Send'),
                            primary_action(values) {
                                // Create the WhatsApp message document
                                frappe.call({
                                    method: "frappe.client.insert",
                                    args: {
                                        doc: {
                                            doctype: 'WhatsApp Message',
                                            to: values.to,
                                            message: values.message,
                                            reference_doctype: "Issue",
                                            reference_name: frm.doc.name,
                                            type: 'Outgoing',
                                            content_type: values.content_type,
                                            attach: values.attach
                                        }
                                    },
                                    callback: function (response) {
                                        if (response.message) {
                                            frappe.msgprint({
                                                title: __('Success'),
                                                indicator: 'green',
                                                message: __('WhatsApp message sent successfully.')
                                            });
                                            d.hide();
                                            frm.refresh(); // Refresh the form
                                        } else {
                                            frappe.msgprint({
                                                title: __('Error'),
                                                indicator: 'red',
                                                message: __('Failed to send WhatsApp message.')
                                            });
                                        }
                                    }
                                });
                            }
                        });

                        d.show();
                    } else {
                        frappe.msgprint({
                            title: __('Error'),
                            indicator: 'red',
                            message: __('Failed to fetch contact details.')
                        });
                    }
                },
                error: function (err) {
                    console.error('Error fetching contact:', err);
                    frappe.msgprint({
                        title: __('Error'),
                        indicator: 'red',
                        message: __('An error occurred while fetching the contact details. Please check the console for details.')
                    });
                }
            });
        });
    }
});

frappe.ui.form.on('Issue', {
    refresh: function(frm) {
        setInterval(function() {
            if (frm.doc.__unsaved) {
                return;
            }
            frm.reload_doc();
        }, 10000); // 10000 milliseconds = 10 seconds
    }
});
